function extractTitle(ad) {
  if (ad.headline && typeof ad.headline === 'object') {
    const t = ad.headline.title || ad.headline.description;
    if (t && !t.includes('{{')) return t;
  }
  if (ad.commentary && ad.commentary.text && !ad.commentary.text.includes('{{')) {
    return ad.commentary.text.substring(0, 80);
  }
  if (ad.snapshot) {
    if (Array.isArray(ad.snapshot.cards) && ad.snapshot.cards.length > 0) {
      for (const card of ad.snapshot.cards) {
        if (card.title && !card.title.includes('{{')) return card.title;
        if (card.body && typeof card.body === 'string' && !card.body.includes('{{')) return card.body.substring(0, 80);
      }
    }
    if (ad.snapshot.title && !ad.snapshot.title.includes('{{')) return ad.snapshot.title;
    if (ad.snapshot.body) {
      const bodyText = typeof ad.snapshot.body === 'object' ? ad.snapshot.body.text : ad.snapshot.body;
      if (bodyText && !bodyText.includes('{{')) return bodyText.substring(0, 80);
    }
  }
  if (typeof ad.title === 'string' && !ad.title.includes('{{')) return ad.title;
  if (typeof ad.ad_title === 'string' && ad.ad_title !== 'N/A') return ad.ad_title;
  return null;
}

function extractDate(ad) {
  if (ad.start_date_string) return ad.start_date_string.split('T')[0];
  if (typeof ad.start_date === 'number' && ad.start_date > 0) return new Date(ad.start_date * 1000).toISOString().split('T')[0];
  if (ad.start) return String(ad.start);
  if (ad.started_at) return String(ad.started_at);
  if (ad.created_at) return String(ad.created_at);
  return 'N/A';
}

function extractEndDate(ad) {
  if (ad.end_date_string) return ad.end_date_string.split('T')[0];
  if (typeof ad.end_date === 'number' && ad.end_date > 0) return new Date(ad.end_date * 1000).toISOString().split('T')[0];
  if (ad.last_seen) return String(ad.last_seen);
  if (ad.ended_at) return String(ad.ended_at);
  return 'N/A';
}

function buildSummary(rows) {
  if (rows.length === 0) return 'No ad data found.';
  const byPlatform = {};
  for (const r of rows) {
    byPlatform[r.platform] = (byPlatform[r.platform] || 0) + 1;
  }
  const platformSummary = Object.entries(byPlatform).map(([p, c]) => `${p}: ${c} ads`).join(', ');
  const dates = rows.map(r => r.campaign_start).filter(d => d && d !== 'N/A').sort();
  const earliest = dates[0] || 'unknown';
  const latest   = dates[dates.length - 1] || 'unknown';
  const titles   = [...new Set(rows.map(r => r.ad_title).filter(Boolean))].slice(0, 5).join('; ');
  return `Total ${rows.length} ads across platforms (${platformSummary}). Date range: ${earliest} to ${latest}. Sample titles: ${titles}`;
}

// ===== MAIN =====

const items = $input.all();
const timelineRows = [];

// FIX: Pull domain & competitor_name from the Loop's current batch item
// The splitInBatches node stores the current item in $('Loop Over Competitors').item
let domain = '';
let competitorName = '';

try {
  const loopItem = $('Loop Over Competitors').item.json;
  domain = loopItem.domain || loopItem.Domain || '';
  competitorName = loopItem.competitor_name || loopItem.Competitor_Name || loopItem.name || loopItem.Name || '';
} catch(e) {
  // fallback: scan all items
  for (const item of items) {
    if (item.json.domain) { domain = item.json.domain; }
    if (item.json.competitor_name) { competitorName = item.json.competitor_name; }
  }
}

for (const item of items) {
  const data = item.json;

  // Facebook/Meta
  if (data.results && Array.isArray(data.results)) {
    const fbAds = data.results.flat();
    for (const ad of fbAds) {
      const title = extractTitle(ad);
      if (!title) continue;
      timelineRows.push({
        platform:       'Meta',
        ad_title:       title,
        campaign_start: extractDate(ad),
        campaign_end:   extractEndDate(ad),
        is_active:      ad.is_active || false
      });
    }
  }

  // LinkedIn / Google
  if (data.ads && Array.isArray(data.ads)) {
    for (const ad of data.ads) {
      let platform = 'Google';
      if (ad.view_details_link && ad.view_details_link.includes('linkedin.com')) {
        platform = 'LinkedIn';
      } else if (ad.headline || ad.commentary) {
        platform = 'LinkedIn';
      }

      const title = extractTitle(ad);
      if (!title) continue;

      timelineRows.push({
        platform:       platform,
        ad_title:       title,
        campaign_start: extractDate(ad),
        campaign_end:   extractEndDate(ad),
        is_active:      ad.is_active || false
      });
    }
  }
}

return [{
  json: {
    domain:           domain,
    competitor_name:  competitorName,
    timeline_rows:    timelineRows,
    timeline_summary: buildSummary(timelineRows)
  }
}];

const items = $input.all();
const rows = [];

let timelineRows = [];
let domain = '';
let competitorName = '';

try {
  const extractData = $('Extract Timeline').first().json;
  timelineRows   = extractData.timeline_rows   || [];
  domain         = extractData.domain          || '';
  competitorName = extractData.competitor_name || '';
} catch(e) {}

for (const ad of timelineRows) {
  rows.push({
    domain,
    competitor_name: competitorName,
    platform:        ad.platform       || 'N/A',
    ad_title:        ad.ad_title       || 'N/A',
    campaign_start:  ad.campaign_start || 'N/A',
    campaign_end:    ad.campaign_end   || 'N/A',
    is_active:       ad.is_active ? 'Yes' : 'No',
    checked_at:      new Date().toISOString()
  });
}

return rows.map(r => ({ json: r }));
